import{Ident,Delim}from"../../tokenizer/index.js";const FULLSTOP=46;export const name="Layer";export const structure={name:String};export function parse(){let t=this.tokenStart,e=this.consume(Ident);for(;this.isDelim(46);)this.eat(Delim),e+="."+this.consume(Ident);return{type:"Layer",loc:this.getLocation(t,this.tokenStart),name:e}}export function generate(t){this.tokenize(t.name)}